async (params, browser) => {
  // Search Bluesky
  await browser.open(`https://bsky.app/search?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('[data-testid=\'postText\'], article, div[tabindex=\'0\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const posts = document.querySelectorAll('[data-testid^="feedItem-by-"], div[tabindex="0"][role="link"]'); for (let i = 0; i < Math.min(posts.length, 15); i++) { const el = posts[i]; const authorEl = el.querySelector('[data-testid="profileHeaderDisplayName"], a[href*="/profile/"] span, div[style*="font-weight"] span'); const handleEl = el.querySelector('a[href*="/profile/"]'); const contentEl = el.querySelector('[data-testid="postText"]'); const timeEl = el.querySelector('time'); const linkEl = el.querySelector('a[href*="/post/"]'); const imgEl = el.querySelector('img[src*="feed_"], img[src*="cdn"]'); const likeBtn = el.querySelector('[data-testid="likeBtn"]'); const replyBtn = el.querySelector('[data-testid="replyBtn"]'); const likesText = likeBtn ? likeBtn.getAttribute('aria-label') || '' : ''; const repliesText = replyBtn ? replyBtn.getAttribute('aria-label') || '' : ''; let handle = ''; if (handleEl) { const href = handleEl.getAttribute('href') || ''; const match = href.match(/\/profile\/([^/]+)/); if (match) handle = match[1]; } results.push({ author: authorEl ? authorEl.textContent.trim() : '', handle: handle, content: contentEl ? contentEl.textContent.trim().substring(0, 500) : '', likes: likesText, replies: repliesText, time: timeEl ? (timeEl.getAttribute('datetime') || timeEl.textContent.trim()) : '', url: linkEl ? linkEl.href : '', has_image: !!imgEl }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
